/* CLARK Logo - base64 data URLs - separated due to size.
   
   Two variants are exported:
   
   - CLARK_LOGO        Original branded logo (color), used in the app header
                       and any non-print UI. Looks correct against the page
                       background and the dark navbar (with invert filter).
   
   - CLARK_LOGO_PRINT  V16.55: print-optimized variant — transparent background,
                       2× upscaled (602×130), LA grayscale+alpha PNG mode.
                       The user-supplied source had a BLACK background (not white
                       as initially assumed); the alpha map was rebuilt with
                       black→transparent so brightness(0) saturate(100%) renders
                       only the letterforms in pure black with no surrounding
                       black rectangle. Edge pixels use a 25–80 luminance ramp
                       for clean anti-aliased letter outlines. */

export const CLARK_LOGO="data:image/png;base64,";
export const CLARK_LOGO_PRINT="data:image/png;base64,";
